import anthropic
import random
import json

client = anthropic.Anthropic()

def sample_and_eval_production_queries(
    query_log: list[dict],
    sample_size: int = 300,
    eval_model: str = "claude-sonnet-5",
) -> dict:
    """
    Samples production queries and runs them through a judge model
    to produce a quality score distribution.
    """
    sample = random.sample(query_log, min(sample_size, len(query_log)))
    scores = []
    for item in sample:
        response = client.messages.create(
            model=eval_model,
            max_tokens=512,
            messages=[{
                "role": "user",
                "content": (
                    "Rate this GenAI response on a 1–5 scale for: "
                    "(1) factual accuracy, (2) completeness, (3) conciseness. "
                    "Return JSON with keys: accuracy, completeness, conciseness, overall. "
                    "Do not explain.

"
                    f"Query: {item['query']}

"
                    f"Response: {item['response']}"
                ),
            }],
        )
        try:
            score = json.loads(response.content[0].text)
            scores.append(score)
        except Exception:
            pass   # skip unparseable responses

    if not scores:
        return {"error": "no parseable scores"}

    def avg(key):
        return round(sum(s[key] for s in scores if key in s) / len(scores), 2)

    return {
        "sample_size": len(scores),
        "avg_accuracy": avg("accuracy"),
        "avg_completeness": avg("completeness"),
        "avg_conciseness": avg("conciseness"),
        "avg_overall": avg("overall"),
        "pct_below_3": round(
            sum(1 for s in scores if s.get("overall", 5) < 3) / len(scores) * 100, 1
        ),
    }

import httpx
from datetime import datetime, timedelta

def generate_review_package(
    feature_id: str,
    review_type: str,       # "24h" | "7d" | "30d" | "90d"
    metrics_api: str = "https://internal.ops/metrics",
    eval_api: str = "https://internal.ops/eval",
) -> dict:
    """
    Pulls all metrics required for a post-launch review and returns
    a structured package that can be rendered into the review document.
    """
    end = datetime.utcnow()
    window_map = {"24h": 1, "7d": 7, "30d": 30, "90d": 90}
    days = window_map[review_type]
    start = end - timedelta(days=days)

    params = {
        "feature_id": feature_id,
        "start": start.isoformat(),
        "end": end.isoformat(),
    }

    reliability = httpx.get(f"{metrics_api}/reliability", params=params).json()
    cost = httpx.get(f"{metrics_api}/cost", params=params).json()
    quality = httpx.get(f"{eval_api}/production-sample", params=params).json()
    support = httpx.get(f"{metrics_api}/support-tickets", params=params).json()

    return {
        "feature_id": feature_id,
        "review_type": review_type,
        "period": {"start": start.isoformat(), "end": end.isoformat()},
        "reliability": {
            "slo_compliance_pct": reliability["slo_compliance"],
            "p99_latency_ms": reliability["p99_latency"],
            "error_rate_pct": reliability["error_rate"],
            "incidents": reliability["incidents"],
        },
        "cost": {
            "total_usd": cost["total"],
            "per_request_usd": cost["per_request"],
            "vs_forecast_pct": cost["vs_forecast_pct"],
        },
        "quality": {
            "eval_score": quality["avg_overall"],
            "thumbs_down_rate_pct": quality["thumbs_down_pct"],
            "sample_size": quality["sample_size"],
        },
        "support": {
            "total_tickets": support["count"],
            "top_categories": support["top_categories"][:3],
        },
    }
